const items = $input.all();

// Filtrer ET mapper en une seule opération
const donnees = items
    .map(item => {
        const row = item.json;
        const facturefrs = row.FactureFrs?.startsWith("FN°") 
            ? row.FactureFrs 
            : "FN°" + (row.FactureFrs || "");

        return {
            Code: row.Code || "",
            DFF: row.DFF || "",
            FactureFrs: facturefrs,
            Date: row.Date || "",
            BR: row.BR || "",
            Nom: ""
        };
    });

return [{
    json: {
        donnees: JSON.stringify(donnees),  // ← stringify it here
        email_expediteur: "astitoumde@gmail.com",
        headless: false
    }
}];
